import { questions } from "../data/questions";

function Dashboard() {
  return (
    <div>
      <h2>Dashboard</h2>

      {questions.map((q) => (
        <div key={q.id} style={{ border: "1px solid black", margin: "10px", padding: "10px" }}>
          <h4>{q.title}</h4>
          <p>{q.description}</p>
          <a href="/answers">View Answer</a>
        </div>
      ))}

      <br />
      <a href="/ask">Ask Question</a>
    </div>
  );
}
export default Dashboard;
